// newCommitsCompareTwoCommitsCmd returns the "commits compare-two-commits" cobra command.
// operationId: compareTwoCommits
func newCommitsCompareTwoCommitsCmd() *cobra.Command {
	var (
		repoSlug         string
		spec             string
		workspace        string
		contextParam     int
		path             string
		ignoreWhitespace bool
		binary           bool
		renames          bool
		merge            bool
		topic            bool
	)

	cmd := &cobra.Command{
		Use:   "compare-two-commits",
		Short: `Compare two commits`,
		Long:  "Produces a raw git-style diff.\n\n#### Single commit spec\n\nIf the `spec` argument to this API is a single commit, the diff is\nproduced against the first parent of the specified commit.\n\n#### Two commit spec\n\nTwo commits separated by `..` may be provided as the `spec`, e.g.,\n`3a8b42..9ff173`. When two commits are provided and the `topic` query\nparameter is true, this API produces a 2-way three dot diff.\nThis is the diff between source commit and the merge base of the source\ncommit and the destination commit. When the `topic` query param is false,\na simple git-style diff is produced.\n\nThe two commits are interpreted as follows:\n\n* First commit: the commit containing the changes we wish to preview\n* Second commit: the commit representing the state to which we want to\n  compare the first commit\n* **Note**: This is the opposite of the order used in `git diff`.\n\n#### Comparison to patches\n\nWhile similar to patches, diffs:\n\n* Don't have a commit header (username, commit message, etc)\n* Support the optional `path=foo/bar.py` query param to filter\n  the diff to just that one file diff\n\n#### Response\n\nThe raw diff is returned as-is, in whatever encoding the files in the\nrepository use. It is not decoded into unicode. As such, the\ncontent-type is `text/plain`.",
		RunE: func(cmd *cobra.Command, args []string) error {
			if repoSlug == "" {
				return fmt.Errorf("--repo-slug is required")
			}
			if spec == "" {
				return fmt.Errorf("--spec is required")
			}
			if workspace == "" {
				return fmt.Errorf("--workspace is required")
			}
			c, err := client.NewClient()
			if err != nil {
				return err
			}
			pathParams := map[string]string{
				"repo_slug": repoSlug,
				"spec":      spec,
				"workspace": workspace,
			}
			queryParams := map[string]string{
				"context":           strconv.Itoa(contextParam),
				"path":              path,
				"ignore_whitespace": strconv.FormatBool(ignoreWhitespace),
				"binary":            strconv.FormatBool(binary),
				"renames":           strconv.FormatBool(renames),
				"merge":             strconv.FormatBool(merge),
				"topic":             strconv.FormatBool(topic),
			}
			body := ""
			return handlers.Dispatch(context.Background(), c, handlers.Request{
				Method:      "GET",
				URLTemplate: "/repositories/{workspace}/{repo_slug}/diff/{spec}",
				PathParams:  pathParams,
				QueryParams: queryParams,
				Body:        body,
				All:         false,
			})
		},
	}
	cmd.Flags().StringVar(&repoSlug, "repo-slug", "", "repo_slug (path parameter)")
	cmd.Flags().StringVar(&spec, "spec", "", "spec (path parameter)")
	cmd.Flags().StringVar(&workspace, "workspace", "", "workspace (path parameter)")
	cmd.Flags().IntVar(&contextParam, "context", 0, "context (query parameter)")
	cmd.Flags().StringVar(&path, "path", "", "path (query parameter)")
	cmd.Flags().BoolVar(&ignoreWhitespace, "ignore-whitespace", false, "ignore_whitespace (query parameter)")
	cmd.Flags().BoolVar(&binary, "binary", false, "binary (query parameter)")
	cmd.Flags().BoolVar(&renames, "renames", false, "renames (query parameter)")
	cmd.Flags().BoolVar(&merge, "merge", false, "merge (query parameter)")
	cmd.Flags().BoolVar(&topic, "topic", false, "topic (query parameter)")
	return cmd
}

